(function(){'use strict';const chartInstances=new Map();const chartModalState={currentChart:null,currentCanvasId:null,modal:null,isOpen:false};function registerChartInstance(canvasId,chartInstance){chartInstances.set(canvasId,chartInstance);console.log('✅ Chart registered:',canvasId,chartInstance);}function getChartInstance(canvasId){const instance=chartInstances.get(canvasId);console.log('🔍 Getting chart instance:',canvasId,instance);return instance;}function initChartModal(){chartModalState.modal=document.getElementById('chartFullscreenModal');console.log('📋 Initializing chart modal...');if(!chartModalState.modal){console.error('❌ chartFullscreenModal not found in DOM');return;}console.log('✅ Chart modal initialized successfully');chartModalState.modal.addEventListener('click',function(event){if(event.target===chartModalState.modal){console.log('🔴 Closing modal via background click');closeChartModal();}});document.addEventListener('keydown',function(event){if(event.key==='Escape'&&chartModalState.isOpen){console.log('🔴 Closing modal via Escape key');closeChartModal();}});}function openChartModal(chartCanvasId,chartTitle){console.log('🔍 Opening chart modal:',chartCanvasId);const modal=document.getElementById('chartFullscreenModal');if(!modal){console.error('❌ Chart modal not found');return;}const titleElement=document.getElementById('chartModalTitle');if(titleElement){titleElement.textContent=chartTitle;}const originalChartInstance=getChartInstance(chartCanvasId);if(!originalChartInstance){console.error('❌ Chart instance not registered:',chartCanvasId);const originalCanvas=document.getElementById(chartCanvasId);if(!originalCanvas||!originalCanvas.__chartjs__){console.error('❌ Chart canvas not found:',chartCanvasId);return;}}const modalCanvas=document.getElementById('chartFullscreenCanvas');if(!modalCanvas){console.error('❌ Modal canvas not found');return;}const ctx=modalCanvas.getContext('2d');let chartConfig;if(originalChartInstance){chartConfig={type:originalChartInstance.config.type,data:JSON.parse(JSON.stringify(originalChartInstance.config.data)),options:JSON.parse(JSON.stringify(originalChartInstance.config.options))};}else{console.error('❌ Cannot get chart configuration');return;}if(chartModalState.currentChart){try{chartModalState.currentChart.destroy();}catch(e){console.warn('⚠️ Error destroying previous chart:',e);}}chartConfig.options=chartConfig.options||{};chartConfig.options.responsive=true;chartConfig.options.maintainAspectRatio=false;chartConfig.options.plugins=chartConfig.options.plugins||{};chartConfig.options.plugins.legend=chartConfig.options.plugins.legend||{position:'bottom'};try{chartModalState.currentChart=new Chart(ctx,chartConfig);chartModalState.currentCanvasId=chartCanvasId;chartModalState.isOpen=true;modal.classList.add('active');setTimeout(()=>{try{window.dispatchEvent(new Event('resize'));if(chartModalState.currentChart&&typeof chartModalState.currentChart.resize==='function'){chartModalState.currentChart.resize();}}catch(e){console.warn('⚠️ Error resizing chart:',e);}},100);console.log('✅ Chart modal opened:',chartTitle);}catch(error){console.error('❌ Error creating fullscreen chart:',error);}}function closeChartModal(){const modal=document.getElementById('chartFullscreenModal');if(modal){modal.classList.remove('active');chartModalState.isOpen=false;if(chartModalState.currentChart){try{chartModalState.currentChart.destroy();chartModalState.currentChart=null;}catch(e){console.warn('⚠️ Error destroying chart:',e);}}console.log('✅ Chart modal closed');}}window.openChartModal=openChartModal;window.closeChartModal=closeChartModal;window.registerChartInstance=registerChartInstance;function initOnReady(){initChartModal();}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initOnReady);}else{initOnReady();}})();